```kotlin
package com.example.thingsappandroid.features.home

import android.content.BroadcastReceiver
import android.content.Context
import android.content.Intent
import android.content.IntentFilter
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.thingsappandroid.data.repository.ThingsRepository
import com.example.thingsappandroid.util.BatteryUtil
import dagger.hilt.android.lifecycle.HiltViewModel
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

data class HomeUiState(
    val batteryLevel: Float = 0f,
    val isCharging: Boolean = false,
    val batteryCapacityMwh: Int? = null,
    val isLoading: Boolean = false,
    val error: String? = null
)

@HiltViewModel
class HomeViewModel @Inject constructor(
    @ApplicationContext private val context: Context,
    private val repository: ThingsRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow(HomeUiState())
    val uiState: StateFlow<HomeUiState> = _uiState.asStateFlow()

    private val batteryReceiver = object : BroadcastReceiver() {
        override fun onReceive(context: Context?, intent: Intent?) {
            if (intent?.action == "com.example.thingsappandroid.BATTERY_CHANGED") {
                val level = intent.getIntExtra("level", 0)
                val isCharging = intent.getBooleanExtra("is_charging", false)

                // Fetch capacity from utility
                val capacity = context?.let { BatteryUtil.getBatteryCapacityMwh(it) }

                _uiState.update { it.copy(
                    // FIX: Use float division to avoid 0% issue
                    batteryLevel = level / 100f,
                    isCharging = isCharging,
                    batteryCapacityMwh = capacity
                )}
            }
        }
    }

    init {
        val filter = IntentFilter("com.example.thingsappandroid.BATTERY_CHANGED")
        context.registerReceiver(batteryReceiver, filter)

        // Proactively request initial state from BatteryService
        requestInitialBatteryState()
    }

    private fun requestInitialBatteryState() {
        val intent = Intent("com.example.thingsappandroid.BATTERY_STATE_REQUEST")
        context.sendBroadcast(intent)
    }

    override fun onCleared() {
        super.onCleared()
        try {
            context.unregisterReceiver(batteryReceiver)
        } catch (e: Exception) {
            // Receiver might not be registered
        }
    }
}
```

