class StationCodeReceiver : BroadcastReceiver() {
    companion object {
        const val OPEN_STATION_CODE_DIALOG_EXTRA = "open_station_code_dialog_from_notification"
    }
    override fun onReceive(context: Context, intent: Intent) {
        try {
            val remoteInput = RemoteInput.getResultsFromIntent(intent)
            val stationCode = remoteInput?.getCharSequence("station_code_input")?.toString()

            if (!stationCode.isNullOrBlank()) {
                Log.d("StationCodeReceiver", "Received station code from notification: $stationCode")

                // Send broadcast to notify BatteryService to update immediately with the code
                val updateIntent = Intent("com.example.thingsappandroid.STATION_CODE_UPDATED")
                updateIntent.apply {
                    putExtra("station_code", stationCode.trim())
                }
                context.sendBroadcast(updateIntent)

                Log.d("StationCodeReceiver", "Broadcast sent to update notification with code")

                // Launch MainActivity to open StationCodeBottomSheet
                openMainActivityForBottomSheet(context)

            } else {
                Log.w("StationCodeReceiver", "No station code received from notification input")
            }
        } catch (e: Exception) {
            Log.e("StationCodeReceiver", "Error processing station code", e)
        }
    }

    private fun openMainActivityForBottomSheet(context: Context) {
        val launchIntent = Intent(context, MainActivity::class.java).apply {
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_SINGLE_TOP)
            putExtra(OPEN_STATION_CODE_DIALOG_EXTRA, true)
        }

        // Create PendingIntent
        val pendingIntent = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            PendingIntent.getActivity(
                context,
                0,
                launchIntent,
                PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
            )
        } else {
            PendingIntent.getActivity(
                context,
                0,
                launchIntent,
                PendingIntent.FLAG_UPDATE_CURRENT
            )
        }

        try {
            pendingIntent.send()
            Log.d("StationCodeReceiver", "PendingIntent sent to open MainActivity.")
        } catch (e: PendingIntent.CanceledException) {
            Log.e("StationCodeReceiver", "PendingIntent was canceled", e)
        }
    }
}
