// app/src/main/java/com/example/thingsappandroid/util/StationCodeBus.kt
package com.example.thingsappandroid.util

import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.asSharedFlow

/**
 * Singleton event bus to communicate Station Code events from Activity to Composable screens.
 */
object StationCodeBus {
    private val _showStationCodeSheet = MutableSharedFlow<Unit>(replay = 0)
    val showStationCodeSheet = _showStationCodeSheet.asSharedFlow()

    suspend fun requestShowStationCodeSheet() {
        _showStationCodeSheet.emit(Unit)
    }
}
