@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun StationCodeBottomSheet(
    onDismiss: () -> Unit
) {
    val sheetState = rememberModalBottomSheetState()
    val context = LocalContext.current
    var stationCode by remember { mutableStateOf("") }

    ModalBottomSheet(
        onDismissRequest = onDismiss,
        sheetState = sheetState
    ) {
        Column(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 24.dp)
                .padding(bottom = 48.dp)
        ) {
            Text(
                text = "Enter Station Code",
                style = MaterialTheme.typography.headlineSmall
            )

            Spacer(modifier = Modifier.height(8.dp))

            Text(
                text = "Please enter the code displayed on the charging station to verify your session.",
                style = MaterialTheme.typography.bodyMedium,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )

            Spacer(modifier = Modifier.height(24.dp))

            OutlinedTextField(
                value = stationCode,
                onValueChange = { stationCode = it },
                label = { Text("Station Code") },
                singleLine = true,
                modifier = Modifier.fillMaxWidth(),
                keyboardOptions = KeyboardOptions(
                    keyboardType = KeyboardType.Text,
                    imeAction = ImeAction.Done
                ),
                keyboardActions = KeyboardActions(
                    onDone = {
                        if (stationCode.isNotBlank()) {
                            submitCode(context, stationCode)
                            onDismiss()
                        }
                    }
                )
            )

            Spacer(modifier = Modifier.height(24.dp))

            Button(
                onClick = {
                    submitCode(context, stationCode)
                    onDismiss()
                },
                modifier = Modifier.fillMaxWidth(),
                enabled = stationCode.isNotBlank()
            ) {
                Text("Verify Code")
            }
        }
    }
}

private fun submitCode(context: android.content.Context, code: String) {
    val updateIntent = Intent("com.example.thingsappandroid.STATION_CODE_UPDATED").apply {
        putExtra("station_code", code.trim())
    }
    context.sendBroadcast(updateIntent)
}
